1→#!/usr/bin/env node
     2→
     3→const { execSync } = require('node:child_process');
     4→const { writeFile, mkdir, access } = require('node:fs/promises');
     5→
     6→const { CODEOWNERS_FILE_PATH, CODEOWNERS_MANIFEST_DIR, METADATA_JSON_PATH } = require('./constants.js');
     7→
     8→/**
     9→ * @typedef {Object} CodeownersMetadata
    10→ * @property {string} generatedAt - ISO timestamp when metadata was generated
    11→ * @property {string} filesHash - SHA-256 hash of all repository files
    12→ * @property {string} codeownersHash - SHA-256 hash of CODEOWNERS file
    13→ */
    14→
    15→/**
    16→ * Generate codeowners metadata for caching
    17→ * @param {string} codeownersFilePath - Path to CODEOWNERS file
    18→ * @param {string} manifestDir - Directory for manifest files
    19→ * @param {string} metadataFilename - Filename for metadata file
    20→ * @returns {CodeownersMetadata} Metadata object with hashes
    21→ */
    22→function generateCodeownersMetadata(codeownersFilePath, manifestDir, metadataFilename) {
    23→  const [filesHash] = execSync('git ls-files --cached --others --exclude-standard | sort | sha256sum', {
    24→    encoding: 'utf8',
    25→  })
    26→    .trim()
    27→    .split(' ');
    28→
    29→  const [codeownersHash] = execSync(`sha256sum "${codeownersFilePath}"`, { encoding: 'utf8' }).trim().split(' ');
    30→
    31→  return {
    32→    generatedAt: new Date().toISOString(),
    33→    filesHash,
    34→    codeownersHash,
    35→  };
    36→}
    37→
    38→if (require.main === module) {
    39→  (async () => {
    40→    try {
    41→      console.log('⚙️ Generating codeowners-manifest metadata ...');
    42→
    43→      try {
    44→        await access(CODEOWNERS_MANIFEST_DIR);
    45→      } catch (error) {
    46→        await mkdir(CODEOWNERS_MANIFEST_DIR, { recursive: true });
    47→      }
    48→
    49→      const metadata = generateCodeownersMetadata(CODEOWNERS_FILE_PATH, CODEOWNERS_MANIFEST_DIR, METADATA_JSON_PATH);
    50→
    51→      await writeFile(METADATA_JSON_PATH, JSON.stringify(metadata, null, 2), 'utf8');
    52→      console.log('✅ Metadata generated:');
    53→      console.log(`   • ${METADATA_JSON_PATH}`);
    54→    } catch (error) {
    55→      console.error('❌ Error generating codeowners metadata:', error.message);
    56→      process.exit(1);
    57→    }
    58→  })();
    59→}
    60→
    61→module.exports = { generateCodeownersMetadata };
